func writeSecretFile(t *testing.T, filename, content string) string {
	t.Helper()
	path := filepath.Join(t.TempDir(), filename)
	if err := os.WriteFile(path, []byte(content), 0o600); err != nil {
		t.Fatalf("write %s: %v", path, err)
	}
	return path
}

func ClientKeyPath(t *testing.T) string {
	t.Helper()
	return writeSecretFile(t, "client.key", ClientKeyContent)
}

func ClientKeyNoPassPath(t *testing.T) string {
	t.Helper()
	return ClientKeyPath(t)
}

func InvalidCA(t *testing.T) string {
	t.Helper()
	return ClientKeyPath(t)
}

func WrongClientKeyPath(t *testing.T) string {
	t.Helper()
	return SelfSignedClientKeyPath(t)
}

func SelfSignedClientKeyPath(t *testing.T) string {
	t.Helper()
	return writeSecretFile(t, "self-signed-client.key", SelfSignedClientKeyContent)
}

func ServerKeyPath(t *testing.T) string {
	t.Helper()
	return writeSecretFile(t, "server.key", ServerKeyContent)
}
